function readCommit(){try{return require('child_process').execSync('git rev-parse --short HEAD',{stdio:['ignore','pipe','ignore']}).toString().trim()}catch{return null}}
function migrate(){
 db.exec(`CREATE TABLE IF NOT EXISTS settings(key TEXT PRIMARY KEY,value TEXT NOT NULL);
 CREATE TABLE IF NOT EXISTS items(id TEXT PRIMARY KEY,name TEXT NOT NULL,cost_cents INTEGER NOT NULL,category TEXT NOT NULL DEFAULT 'Uncategorized',active INTEGER NOT NULL DEFAULT 1,sku TEXT,notes TEXT,updated_at TEXT NOT NULL);
 CREATE TABLE IF NOT EXISTS campers(id TEXT PRIMARY KEY,name TEXT NOT NULL,person_type TEXT NOT NULL DEFAULT 'Camper',initial_balance_cents INTEGER NOT NULL,current_balance_cents INTEGER NOT NULL,sheet_row INTEGER,active INTEGER NOT NULL DEFAULT 1,notes TEXT,source TEXT NOT NULL DEFAULT 'google',updated_at TEXT NOT NULL);
 CREATE TABLE IF NOT EXISTS transactions(id TEXT PRIMARY KEY,created_at TEXT NOT NULL,clerk TEXT,camper_id TEXT,camper_name TEXT,previous_balance_cents INTEGER,total_cents INTEGER NOT NULL,new_balance_cents INTEGER,items_json TEXT NOT NULL,sync_status TEXT NOT NULL DEFAULT 'pending',synced_at TEXT,error TEXT,sale_type TEXT NOT NULL DEFAULT 'account',payment_method TEXT NOT NULL DEFAULT 'account',cash_box_session_id INTEGER,cash_received_cents INTEGER,change_given_cents INTEGER,client_request_id TEXT UNIQUE,FOREIGN KEY(camper_id) REFERENCES campers(id));
 CREATE TABLE IF NOT EXISTS sync_events(id INTEGER PRIMARY KEY AUTOINCREMENT,created_at TEXT NOT NULL,type TEXT NOT NULL,status TEXT NOT NULL,message TEXT);
 CREATE TABLE IF NOT EXISTS balance_adjustments(id TEXT PRIMARY KEY,created_at TEXT NOT NULL,admin TEXT,camper_id TEXT NOT NULL,camper_name TEXT NOT NULL,action TEXT NOT NULL,amount_cents INTEGER,previous_balance_cents INTEGER NOT NULL,new_balance_cents INTEGER NOT NULL,reason TEXT NOT NULL,sync_status TEXT NOT NULL DEFAULT 'pending',synced_at TEXT,error TEXT);
 CREATE TABLE IF NOT EXISTS audit_logs(id TEXT PRIMARY KEY,created_at TEXT NOT NULL,admin TEXT,action TEXT NOT NULL,person_id TEXT,person_name TEXT,initial_balance_cents INTEGER,current_balance_cents INTEGER,details_json TEXT);
 CREATE TABLE IF NOT EXISTS account_ledger(id INTEGER PRIMARY KEY AUTOINCREMENT,camper_id TEXT NOT NULL,entry_type TEXT NOT NULL,amount_cents INTEGER NOT NULL,balance_before_cents INTEGER NOT NULL,balance_after_cents INTEGER NOT NULL,payment_method TEXT,reason TEXT,transaction_id TEXT,balance_adjustment_id TEXT,audit_log_id TEXT,created_by_user_id TEXT,created_by_name TEXT,created_at TEXT NOT NULL,metadata_json TEXT,FOREIGN KEY(camper_id) REFERENCES campers(id),FOREIGN KEY(transaction_id) REFERENCES transactions(id),FOREIGN KEY(balance_adjustment_id) REFERENCES balance_adjustments(id),FOREIGN KEY(audit_log_id) REFERENCES audit_logs(id),FOREIGN KEY(created_by_user_id) REFERENCES users(id));
 CREATE TABLE IF NOT EXISTS cash_events(id TEXT PRIMARY KEY,account_ledger_id INTEGER,camper_id TEXT,event_type TEXT NOT NULL,amount_credited_cents INTEGER NOT NULL DEFAULT 0,cash_received_cents INTEGER NOT NULL,change_given_cents INTEGER NOT NULL,reason TEXT,created_by_user_id TEXT,created_by_name TEXT,created_at TEXT NOT NULL,client_request_id TEXT UNIQUE,cash_box_session_id INTEGER,transaction_id TEXT,sale_total_cents INTEGER NOT NULL DEFAULT 0,net_drawer_change_cents INTEGER NOT NULL DEFAULT 0,FOREIGN KEY(account_ledger_id) REFERENCES account_ledger(id),FOREIGN KEY(camper_id) REFERENCES campers(id),FOREIGN KEY(created_by_user_id) REFERENCES users(id),FOREIGN KEY(transaction_id) REFERENCES transactions(id));
 CREATE TABLE IF NOT EXISTS users(id TEXT PRIMARY KEY,username TEXT NOT NULL UNIQUE,display_name TEXT NOT NULL,role TEXT NOT NULL CHECK(role IN ('OWNER','ADMIN','CLERK')),password_hash TEXT NOT NULL,active INTEGER NOT NULL DEFAULT 1,created_at TEXT NOT NULL,updated_at TEXT NOT NULL);`);

 // Existing databases may have older tables. Add columns before any SQL below
 // references them (especially items.category in the category index/status queries).
 ensureColumn('items','category',"TEXT NOT NULL DEFAULT 'Uncategorized'");
 ensureColumn('items','active',"INTEGER NOT NULL DEFAULT 1");
 ensureColumn('items','sku',"TEXT");
 ensureColumn('items','notes',"TEXT");
 ensureColumn('campers','person_type',"TEXT NOT NULL DEFAULT 'Camper'");
 ensureColumn('campers','active',"INTEGER NOT NULL DEFAULT 1");
 ensureColumn('campers','notes',"TEXT");
 ensureColumn('campers','source',"TEXT NOT NULL DEFAULT 'google'");
 ensureColumn('campers','cabin',"TEXT");
 ensureColumn('campers','external_id',"TEXT");
 ensureColumn('items','stock_qty',"INTEGER");
 ensureColumn('users','active',"INTEGER NOT NULL DEFAULT 1");
 db.exec(`CREATE TABLE IF NOT EXISTS cash_box_sessions(id INTEGER PRIMARY KEY AUTOINCREMENT,opening_amount_cents INTEGER NOT NULL CHECK(opening_amount_cents >= 0),opened_at TEXT NOT NULL,opened_by_user_id TEXT,opened_by_name TEXT NOT NULL,status TEXT NOT NULL DEFAULT 'open' CHECK(status IN ('open','closed')),closed_at TEXT,closed_by_user_id TEXT,closed_by_name TEXT,notes TEXT,FOREIGN KEY(opened_by_user_id) REFERENCES users(id),FOREIGN KEY(closed_by_user_id) REFERENCES users(id));`);
 ensureNullableTransactionsAndCashEvents();
 repairStaleNullableForeignKeys();
 ensureColumn('transactions','sale_type',"TEXT NOT NULL DEFAULT 'account'");
 ensureColumn('transactions','payment_method',"TEXT NOT NULL DEFAULT 'account'");
 ensureColumn('transactions','cash_box_session_id',"INTEGER");
 ensureColumn('transactions','cash_received_cents',"INTEGER");
 ensureColumn('transactions','change_given_cents',"INTEGER");
 ensureColumn('transactions','client_request_id',"TEXT");
 ensureColumn('cash_events','cash_box_session_id',"INTEGER");
 ensureColumn('cash_events','transaction_id',"TEXT");
 ensureColumn('cash_events','sale_total_cents',"INTEGER NOT NULL DEFAULT 0");
 ensureColumn('cash_events','net_drawer_change_cents',"INTEGER NOT NULL DEFAULT 0");
 db.exec(`CREATE TABLE IF NOT EXISTS user_page_permissions(id INTEGER PRIMARY KEY AUTOINCREMENT,user_id TEXT NOT NULL,permission_key TEXT NOT NULL,allowed INTEGER NOT NULL CHECK(allowed IN (0,1)),created_at TEXT NOT NULL,updated_at TEXT NOT NULL,FOREIGN KEY(user_id) REFERENCES users(id) ON DELETE CASCADE,UNIQUE(user_id,permission_key));
 CREATE INDEX IF NOT EXISTS idx_user_page_permissions_user ON user_page_permissions(user_id);
 CREATE INDEX IF NOT EXISTS idx_user_page_permissions_key ON user_page_permissions(permission_key);
 CREATE TABLE IF NOT EXISTS cash_box_sessions(id INTEGER PRIMARY KEY AUTOINCREMENT,opening_amount_cents INTEGER NOT NULL CHECK(opening_amount_cents >= 0),opened_at TEXT NOT NULL,opened_by_user_id TEXT,opened_by_name TEXT NOT NULL,status TEXT NOT NULL DEFAULT 'open' CHECK(status IN ('open','closed')),closed_at TEXT,closed_by_user_id TEXT,closed_by_name TEXT,notes TEXT,FOREIGN KEY(opened_by_user_id) REFERENCES users(id),FOREIGN KEY(closed_by_user_id) REFERENCES users(id));
 CREATE UNIQUE INDEX IF NOT EXISTS idx_cash_box_sessions_one_open ON cash_box_sessions(status) WHERE status='open';
 CREATE TABLE IF NOT EXISTS cash_box_adjustments(id INTEGER PRIMARY KEY AUTOINCREMENT,cash_box_session_id INTEGER NOT NULL,adjustment_type TEXT NOT NULL CHECK(adjustment_type IN ('cash_added','cash_removed','initial_correction')),amount_cents INTEGER NOT NULL CHECK(amount_cents >= 0),reason TEXT NOT NULL,created_by_user_id TEXT,created_by_name TEXT NOT NULL,created_at TEXT NOT NULL,metadata_json TEXT,FOREIGN KEY(cash_box_session_id) REFERENCES cash_box_sessions(id),FOREIGN KEY(created_by_user_id) REFERENCES users(id));
 CREATE INDEX IF NOT EXISTS idx_cash_box_adjustments_session ON cash_box_adjustments(cash_box_session_id);
 CREATE TABLE IF NOT EXISTS stock_adjustments(id TEXT PRIMARY KEY,item_id TEXT NOT NULL,quantity_change INTEGER NOT NULL CHECK(quantity_change > 0),resulting_quantity INTEGER NOT NULL,adjustment_type TEXT NOT NULL,reason TEXT,user_id TEXT,created_at TEXT NOT NULL,FOREIGN KEY(item_id) REFERENCES items(id),FOREIGN KEY(user_id) REFERENCES users(id));
 CREATE INDEX IF NOT EXISTS idx_stock_adjustments_item ON stock_adjustments(item_id);
 CREATE INDEX IF NOT EXISTS idx_stock_adjustments_user ON stock_adjustments(user_id);`);

 db.exec(`CREATE INDEX IF NOT EXISTS idx_campers_name ON campers(name);
 CREATE INDEX IF NOT EXISTS idx_campers_cabin ON campers(cabin);
 CREATE INDEX IF NOT EXISTS idx_campers_external ON campers(external_id);
 CREATE INDEX IF NOT EXISTS idx_users_username ON users(username);
 CREATE INDEX IF NOT EXISTS idx_account_ledger_camper ON account_ledger(camper_id);
 CREATE INDEX IF NOT EXISTS idx_account_ledger_created ON account_ledger(created_at);
 CREATE INDEX IF NOT EXISTS idx_account_ledger_transaction ON account_ledger(transaction_id);
 CREATE INDEX IF NOT EXISTS idx_account_ledger_adjustment ON account_ledger(balance_adjustment_id);
 CREATE INDEX IF NOT EXISTS idx_cash_events_ledger ON cash_events(account_ledger_id);
 CREATE INDEX IF NOT EXISTS idx_cash_events_camper ON cash_events(camper_id);
 CREATE INDEX IF NOT EXISTS idx_cash_events_created ON cash_events(created_at);`);
 backfillAccountLedger();
 ensureItemsNameCategoryIndex();
 setDefault('allow_over_balance', String(process.env.ALLOW_OVER_BALANCE === 'true'));
}
function q(name){return '"'+String(name).replace(/"/g,'""')+'"'}
function tableExists(name){return !!db.prepare("SELECT 1 FROM sqlite_master WHERE type='table' AND name=?").get(name)}
function tableInfo(table){return tableExists(table)?db.prepare(`PRAGMA table_info(${q(table)})`).all():[]}
function foreignKeyList(table){return tableExists(table)?db.prepare(`PRAGMA foreign_key_list(${q(table)})`).all():[]}
function indexList(table){return tableExists(table)?db.prepare(`PRAGMA index_list(${q(table)})`).all():[]}
function columnMap(table){return Object.fromEntries(tableInfo(table).map(c=>[c.name,c]))}
function isNullable(table,column){const c=columnMap(table)[column]; return c && !c.notnull}
function needsNullableTransactionMigration(){return ['camper_id','camper_name','previous_balance_cents','new_balance_cents'].some(c=>columnMap('transactions')[c]?.notnull)}
function needsNullableCashEventsMigration(){return ['account_ledger_id','camper_id','cash_box_session_id','transaction_id'].some(c=>columnMap('cash_events')[c]?.notnull)}
function countRows(table){return tableExists(table)?db.prepare(`SELECT count(*) c FROM ${q(table)}`).get().c:0}
function idSet(table){return db.prepare(`SELECT group_concat(id, char(10)) ids FROM (SELECT id FROM ${q(table)} ORDER BY id)`).get().ids||''}
function assertNoForeignKeyViolations(){const rows=db.prepare('PRAGMA foreign_key_check').all(); if(rows.length) throw Error('[migration] Foreign-key validation failed: '+JSON.stringify(rows)); console.log('[migration] Foreign-key validation passed')}
function validateNoInterruptedNullableMigration(){
 const leftovers=['transactions_old_nullable','transactions_new','cash_events_old_nullable','cash_events_new'].filter(tableExists);
 if(!leftovers.length) return;
 const details=leftovers.map(t=>`${t}: rows=${countRows(t)}, columns=${tableInfo(t).map(c=>c.name).join(',')}`).join('; ');
 throw Error(`[migration] Interrupted nullable cash-sale migration detected (${details}). Restore from backup or inspect these tables manually; refusing to guess which financial records are authoritative.`);
}
function createAccountLedgerTable(name){db.exec(`CREATE TABLE ${q(name)}(id INTEGER PRIMARY KEY AUTOINCREMENT,camper_id TEXT NOT NULL,entry_type TEXT NOT NULL,amount_cents INTEGER NOT NULL,balance_before_cents INTEGER NOT NULL,balance_after_cents INTEGER NOT NULL,payment_method TEXT,reason TEXT,transaction_id TEXT,balance_adjustment_id TEXT,audit_log_id TEXT,created_by_user_id TEXT,created_by_name TEXT,created_at TEXT NOT NULL,metadata_json TEXT,FOREIGN KEY(camper_id) REFERENCES campers(id),FOREIGN KEY(transaction_id) REFERENCES transactions(id),FOREIGN KEY(balance_adjustment_id) REFERENCES balance_adjustments(id),FOREIGN KEY(audit_log_id) REFERENCES audit_logs(id),FOREIGN KEY(created_by_user_id) REFERENCES users(id))`)}
function createTransactionsTable(name){db.exec(`CREATE TABLE ${q(name)}(id TEXT PRIMARY KEY,created_at TEXT NOT NULL,clerk TEXT,camper_id TEXT,camper_name TEXT,previous_balance_cents INTEGER,total_cents INTEGER NOT NULL,new_balance_cents INTEGER,items_json TEXT NOT NULL,sync_status TEXT NOT NULL DEFAULT 'pending',synced_at TEXT,error TEXT,sale_type TEXT NOT NULL DEFAULT 'account',payment_method TEXT NOT NULL DEFAULT 'account',cash_box_session_id INTEGER,cash_received_cents INTEGER,change_given_cents INTEGER,client_request_id TEXT UNIQUE,discount_cents INTEGER NOT NULL DEFAULT 0,FOREIGN KEY(camper_id) REFERENCES campers(id),FOREIGN KEY(cash_box_session_id) REFERENCES cash_box_sessions(id))`)}
function createCashEventsTable(name){db.exec(`CREATE TABLE ${q(name)}(id TEXT PRIMARY KEY,account_ledger_id INTEGER,camper_id TEXT,event_type TEXT NOT NULL,amount_credited_cents INTEGER NOT NULL DEFAULT 0,cash_received_cents INTEGER NOT NULL,change_given_cents INTEGER NOT NULL,reason TEXT,created_by_user_id TEXT,created_by_name TEXT,created_at TEXT NOT NULL,client_request_id TEXT UNIQUE,cash_box_session_id INTEGER,transaction_id TEXT,sale_total_cents INTEGER NOT NULL DEFAULT 0,net_drawer_change_cents INTEGER NOT NULL DEFAULT 0,FOREIGN KEY(account_ledger_id) REFERENCES account_ledger(id),FOREIGN KEY(camper_id) REFERENCES campers(id),FOREIGN KEY(created_by_user_id) REFERENCES users(id),FOREIGN KEY(cash_box_session_id) REFERENCES cash_box_sessions(id),FOREIGN KEY(transaction_id) REFERENCES transactions(id))`)}
function selectExpression(source,column,def){return columnMap(source)[column]?q(column):def+' AS '+q(column)}
function copyTable(source,target,columns,defaults){
 const exprs=columns.map(c=>selectExpression(source,c,defaults[c]??'NULL')).join(',');
 db.exec(`INSERT INTO ${q(target)}(${columns.map(q).join(',')}) SELECT ${exprs} FROM ${q(source)}`);
}
function recreateNullableIndexes(){db.exec(`CREATE INDEX IF NOT EXISTS idx_transactions_camper ON transactions(camper_id);
 CREATE INDEX IF NOT EXISTS idx_transactions_created ON transactions(created_at);
 CREATE INDEX IF NOT EXISTS idx_transactions_sync ON transactions(sync_status);
 CREATE INDEX IF NOT EXISTS idx_transactions_cash_box_session ON transactions(cash_box_session_id);
 CREATE UNIQUE INDEX IF NOT EXISTS idx_transactions_client_request_id ON transactions(client_request_id) WHERE client_request_id IS NOT NULL;
 CREATE INDEX IF NOT EXISTS idx_cash_events_ledger ON cash_events(account_ledger_id);
 CREATE INDEX IF NOT EXISTS idx_cash_events_camper ON cash_events(camper_id);
 CREATE INDEX IF NOT EXISTS idx_cash_events_created ON cash_events(created_at);
 CREATE INDEX IF NOT EXISTS idx_cash_events_transaction ON cash_events(transaction_id);
 CREATE INDEX IF NOT EXISTS idx_cash_events_cash_box_session ON cash_events(cash_box_session_id);
 CREATE UNIQUE INDEX IF NOT EXISTS idx_cash_events_client_request_id ON cash_events(client_request_id) WHERE client_request_id IS NOT NULL;`)}
function validateMigrationRowCounts(before){
 const after={transactions:countRows('transactions'),cash_events:countRows('cash_events'),account_ledger:countRows('account_ledger')};
 for(const t of Object.keys(before.counts)) if(before.counts[t]!==after[t]) throw Error(`[migration] ${t} row count changed from ${before.counts[t]} to ${after[t]}`);
 if(before.transactionIds!=null&&before.transactionIds!==idSet('transactions')) throw Error('[migration] Transaction IDs changed during nullable migration');
 if(before.cashEventIds!=null&&before.cashEventIds!==idSet('cash_events')) throw Error('[migration] Cash event IDs changed during nullable migration');
 if(before.accountLedgerIds!=null&&before.accountLedgerIds!==idSet('account_ledger')) throw Error('[migration] Account ledger IDs changed during stale foreign-key repair');
 const badLedger=db.prepare('SELECT count(*) c FROM account_ledger l LEFT JOIN transactions t ON t.id=l.transaction_id WHERE l.transaction_id IS NOT NULL AND t.id IS NULL').get().c;
 const badCash=db.prepare('SELECT count(*) c FROM cash_events ce LEFT JOIN transactions t ON t.id=ce.transaction_id WHERE ce.transaction_id IS NOT NULL AND t.id IS NULL').get().c;
 if(badLedger||badCash) throw Error(`[migration] Unresolved transaction references after migration: account_ledger=${badLedger}, cash_events=${badCash}`);
 console.log(`[migration] Row counts before/after: transactions ${before.counts.transactions}/${after.transactions}, cash_events ${before.counts.cash_events}/${after.cash_events}, account_ledger ${before.counts.account_ledger}/${after.account_ledger}`);
}

function tableSql(name){return db.prepare("SELECT sql FROM sqlite_master WHERE type='table' AND name=?").get(name)?.sql||''}
function schemaMentionsOldNullable(table){return tableSql(table).includes('transactions_old_nullable')||foreignKeyList(table).some(r=>String(r.table).includes('transactions_old_nullable'))}
function assertNoOldNullableReferences(){
 const schemaRows=db.prepare("SELECT type,name,sql FROM sqlite_master WHERE sql LIKE '%transactions_old_nullable%'").all();
 if(schemaRows.length) throw Error('[migration] Schema still references transactions_old_nullable: '+schemaRows.map(r=>`${r.type}:${r.name}`).join(', '));
 for(const table of ['transactions','account_ledger','cash_events','cash_box_sessions','cash_box_adjustments']) for(const r of foreignKeyList(table)) if(String(r.table).includes('transactions_old_nullable')) throw Error(`[migration] ${table}.${r.from} still references ${r.table}.${r.to}`);
}
function repairStaleNullableForeignKeys(){
 const candidates=['account_ledger','cash_events'].filter(t=>tableExists(t)&&schemaMentionsOldNullable(t));
 if(!candidates.length){assertNoOldNullableReferences(); return}
 for(const table of ['transactions','account_ledger','cash_events','cash_box_sessions','cash_box_adjustments']) for(const r of foreignKeyList(table)) if(String(r.table).includes('transactions_old_nullable')) console.log(`[migration] Stale foreign key detected: ${table}.${r.from} -> ${r.table}.${r.to}`);
 const before={counts:{transactions:countRows('transactions'),cash_events:countRows('cash_events'),account_ledger:countRows('account_ledger')},transactionIds:idSet('transactions'),cashEventIds:idSet('cash_events'),accountLedgerIds:idSet('account_ledger')};
 const originalFk=db.pragma('foreign_keys',{simple:true});
 try{
  db.pragma('foreign_keys = OFF');
  const run=db.transaction(()=>{
   if(candidates.includes('cash_events')){console.log('[migration] Repairing stale cash_events transaction foreign key'); db.exec('ALTER TABLE cash_events RENAME TO cash_events_stale_fk'); createCashEventsTable('cash_events'); copyTable('cash_events_stale_fk','cash_events',['id','account_ledger_id','camper_id','event_type','amount_credited_cents','cash_received_cents','change_given_cents','reason','created_by_user_id','created_by_name','created_at','client_request_id','cash_box_session_id','transaction_id','sale_total_cents','net_drawer_change_cents'],{amount_credited_cents:'0',sale_total_cents:'0',net_drawer_change_cents:'0'}); console.log(`[migration] Copied ${countRows('cash_events')} cash events`); db.exec('DROP TABLE cash_events_stale_fk')}
   if(candidates.includes('account_ledger')){console.log('[migration] Repairing stale account_ledger transaction foreign key'); db.exec('ALTER TABLE account_ledger RENAME TO account_ledger_stale_fk'); createAccountLedgerTable('account_ledger'); copyTable('account_ledger_stale_fk','account_ledger',['id','camper_id','entry_type','amount_cents','balance_before_cents','balance_after_cents','payment_method','reason','transaction_id','balance_adjustment_id','audit_log_id','created_by_user_id','created_by_name','created_at','metadata_json'],{}); console.log(`[migration] Copied ${countRows('account_ledger')} account ledger rows`); db.exec('DROP TABLE account_ledger_stale_fk')}
   recreateNullableIndexes();
  });
  run();
  validateMigrationRowCounts(before);
  console.log('[migration] Verified transaction references');
  const badCashLedger=db.prepare('SELECT count(*) c FROM cash_events ce LEFT JOIN account_ledger l ON l.id=ce.account_ledger_id WHERE ce.account_ledger_id IS NOT NULL AND l.id IS NULL').get().c;
  if(badCashLedger) throw Error(`[migration] Unresolved account-ledger references after stale foreign-key repair: cash_events=${badCashLedger}`);
  assertNoForeignKeyViolations();
  assertNoOldNullableReferences();
 } finally { db.pragma(`foreign_keys = ${originalFk?1:0}`) }
}

function ensureNullableTransactionsAndCashEvents(){
 validateNoInterruptedNullableMigration();
 const rebuildTx=needsNullableTransactionMigration();
 const rebuildCash=needsNullableCashEventsMigration();
 const rebuildLedger=rebuildTx;
 if(!rebuildTx&&!rebuildCash) return;
 console.log('[migration] Foreign-key graph for nullable cash-sale migration: account_ledger.transaction_id -> transactions.id; cash_events.transaction_id -> transactions.id; cash_events.account_ledger_id -> account_ledger.id; transactions.camper_id, cash_events.camper_id, account_ledger.camper_id -> campers.id; cash_events.created_by_user_id -> users.id; transactions.cash_box_session_id and cash_events.cash_box_session_id -> cash_box_sessions.id when present. Renaming transactions rewrites dependent FKs to transactions_old_nullable, so dropping it fails while account_ledger/cash_events reference it.');
 const before={counts:{transactions:countRows('transactions'),cash_events:countRows('cash_events'),account_ledger:countRows('account_ledger')},transactionIds:idSet('transactions'),cashEventIds:idSet('cash_events')};
 const originalFk=db.pragma('foreign_keys',{simple:true});
 try{
  db.pragma('foreign_keys = OFF');
  const run=db.transaction(()=>{
   if(rebuildCash){console.log('[migration] Rebuilding cash_events'); db.exec('ALTER TABLE cash_events RENAME TO cash_events_old_nullable')}
   if(rebuildLedger){console.log('[migration] Rebuilding account_ledger to refresh transaction foreign key'); db.exec('ALTER TABLE account_ledger RENAME TO account_ledger_old_nullable')}
   if(rebuildTx){console.log('[migration] Rebuilding transactions for nullable camper fields'); db.exec('ALTER TABLE transactions RENAME TO transactions_old_nullable')}
   if(rebuildTx){createTransactionsTable('transactions'); copyTable('transactions_old_nullable','transactions',['id','created_at','clerk','camper_id','camper_name','previous_balance_cents','total_cents','new_balance_cents','items_json','sync_status','synced_at','error','sale_type','payment_method','cash_box_session_id','cash_received_cents','change_given_cents','client_request_id','discount_cents'],{sync_status:"'pending'",sale_type:"'account'",payment_method:"'account'",discount_cents:'0'}); console.log(`[migration] Copied ${countRows('transactions')} transactions`); db.exec('DROP TABLE transactions_old_nullable')}
   if(rebuildLedger){createAccountLedgerTable('account_ledger'); copyTable('account_ledger_old_nullable','account_ledger',['id','camper_id','entry_type','amount_cents','balance_before_cents','balance_after_cents','payment_method','reason','transaction_id','balance_adjustment_id','audit_log_id','created_by_user_id','created_by_name','created_at','metadata_json'],{}); console.log(`[migration] Copied ${countRows('account_ledger')} account ledger rows`); db.exec('DROP TABLE account_ledger_old_nullable')}
   if(rebuildCash){createCashEventsTable('cash_events'); copyTable('cash_events_old_nullable','cash_events',['id','account_ledger_id','camper_id','event_type','amount_credited_cents','cash_received_cents','change_given_cents','reason','created_by_user_id','created_by_name','created_at','client_request_id','cash_box_session_id','transaction_id','sale_total_cents','net_drawer_change_cents'],{amount_credited_cents:'0',sale_total_cents:'0',net_drawer_change_cents:'0'}); console.log(`[migration] Copied ${countRows('cash_events')} cash events`); db.exec('DROP TABLE cash_events_old_nullable')}
   recreateNullableIndexes();
  });
  run();
  validateMigrationRowCounts(before);
  assertNoForeignKeyViolations();
  for(const r of [...foreignKeyList('account_ledger'),...foreignKeyList('cash_events'),...foreignKeyList('transactions')]) if(String(r.table).includes('_old_nullable')) throw Error('[migration] Foreign key still references '+r.table);
 } finally { db.pragma(`foreign_keys = ${originalFk?1:0}`) }
}
function tableColumns(table){return db.prepare(`PRAGMA table_info(${table})`).all().map(c=>c.name)}
function ensureColumn(table,column,definition){const cols=tableColumns(table); if(!cols.includes(column)){db.exec(`ALTER TABLE ${table} ADD COLUMN ${column} ${definition}`); console.log(`[migration] Added ${table}.${column}`)} else console.log(`[migration] ${table}.${column} already exists`)}
function ensureItemsNameCategoryIndex(){const duplicates=db.prepare('SELECT lower(name) name_key, lower(category) category_key, count(*) c FROM items GROUP BY lower(name), lower(category) HAVING c > 1 LIMIT 1').get(); if(duplicates){console.log('[migration] Skipped idx_items_name_category because duplicate item names/categories already exist'); return} db.exec('CREATE UNIQUE INDEX IF NOT EXISTS idx_items_name_category ON items(lower(name),lower(category))'); console.log('[migration] Ensured idx_items_name_category')}
function setDefault(k,v){db.prepare('INSERT OR IGNORE INTO settings(key,value) VALUES(?,?)').run(k,v)}
function jsonOrNull(value){return value==null?null:(typeof value==='string'?value:JSON.stringify(value))}
function insertAccountLedger(conn,entry){const info=conn.prepare('INSERT INTO account_ledger(camper_id,entry_type,amount_cents,balance_before_cents,balance_after_cents,payment_method,reason,transaction_id,balance_adjustment_id,audit_log_id,created_by_user_id,created_by_name,created_at,metadata_json) VALUES(?,?,?,?,?,?,?,?,?,?,?,?,?,?)').run(entry.camper_id,entry.entry_type,entry.amount_cents,entry.balance_before_cents,entry.balance_after_cents,entry.payment_method||null,entry.reason||null,entry.transaction_id||null,entry.balance_adjustment_id||null,entry.audit_log_id||null,entry.created_by_user_id||null,entry.created_by_name||null,entry.created_at||now(),jsonOrNull(entry.metadata_json)); return conn.prepare('SELECT * FROM account_ledger WHERE id=?').get(info.lastInsertRowid)}
function recordOpeningLedger(conn,{camperId,balanceCents,auditLogId,user,createdAt,metadata}){if(!balanceCents) return null; return insertAccountLedger(conn,{camper_id:camperId,entry_type:'opening_balance',amount_cents:balanceCents,balance_before_cents:0,balance_after_cents:balanceCents,audit_log_id:auditLogId,created_by_user_id:user?.id||null,created_by_name:user?.displayName||user?.display_name||null,created_at:createdAt,metadata_json:{zero_entry_policy:'omit_zero_opening_balance',...(metadata||{})}})}
function applyBalanceChange(conn,{camperId,entryType,deltaCents,setBalanceCents,paymentMethod,reason,transactionId,balanceAdjustmentId,auditLogId,user,createdAt,metadata}){const camper=conn.prepare('SELECT * FROM campers WHERE id=?').get(camperId); if(!camper) throw Error('Camper not found'); const before=camper.current_balance_cents; const after=setBalanceCents!==undefined&&setBalanceCents!==null?setBalanceCents:before+deltaCents; const amount=after-before; if(entryType==='purchase'&&amount>=0) throw Error('Purchase ledger amount must be negative'); if(entryType==='funds_added'&&amount<=0) throw Error('Funds-added ledger amount must be positive'); conn.prepare('UPDATE campers SET current_balance_cents=?,updated_at=? WHERE id=?').run(after,createdAt||now(),camperId); const ledger=insertAccountLedger(conn,{camper_id:camperId,entry_type:entryType,amount_cents:amount,balance_before_cents:before,balance_after_cents:after,payment_method:paymentMethod,reason,transaction_id:transactionId,balance_adjustment_id:balanceAdjustmentId,audit_log_id:auditLogId,created_by_user_id:user?.id||null,created_by_name:user?.displayName||user?.display_name||null,created_at:createdAt,metadata_json:metadata}); return {camper:conn.prepare('SELECT * FROM campers WHERE id=?').get(camperId),ledger}}
function backfillAccountLedger(){
 db.prepare("INSERT INTO account_ledger(camper_id,entry_type,amount_cents,balance_before_cents,balance_after_cents,transaction_id,created_by_name,created_at,metadata_json) SELECT t.camper_id,'purchase',t.new_balance_cents-t.previous_balance_cents,t.previous_balance_cents,t.new_balance_cents,t.id,t.clerk,t.created_at,json_object('backfilled',1,'source','transactions') FROM transactions t WHERE t.camper_id IS NOT NULL AND NOT EXISTS (SELECT 1 FROM account_ledger l WHERE l.transaction_id=t.id)").run();
 db.prepare("INSERT INTO account_ledger(camper_id,entry_type,amount_cents,balance_before_cents,balance_after_cents,balance_adjustment_id,created_by_name,reason,created_at,metadata_json) SELECT a.camper_id,CASE WHEN a.action='add' THEN 'funds_added' WHEN a.action='subtract' THEN 'funds_subtracted' WHEN a.action='set' THEN 'balance_set' WHEN a.action LIKE 'reconcile_%' THEN 'reconciliation' ELSE 'manual_adjustment' END,a.new_balance_cents-a.previous_balance_cents,a.previous_balance_cents,a.new_balance_cents,a.id,a.admin,a.reason,a.created_at,json_object('backfilled',1,'source','balance_adjustments') FROM balance_adjustments a WHERE NOT EXISTS (SELECT 1 FROM account_ledger l WHERE l.balance_adjustment_id=a.id)").run();
}

function seedDefaultOwner(){const existingCount=db.prepare('SELECT count(*) c FROM users').get().c; if(existingCount>0) return {seeded:false,reason:'users-exist'}; const username=process.env.DEFAULT_OWNER_USERNAME, password=process.env.DEFAULT_OWNER_PASSWORD; if(!username||!password) return {seeded:false,reason:'missing-env'}; const display=process.env.DEFAULT_OWNER_DISPLAY_NAME||username; const stamp=now(); db.prepare('INSERT INTO users(id,username,display_name,role,password_hash,active,created_at,updated_at) VALUES(?,?,?,?,?,?,?,?)').run('user_'+nanoid(),username,display,'OWNER',hashPassword(password),1,stamp,stamp); return {seeded:true,username}}
function hashPassword(password){const salt=randomBytes(16).toString('hex'); const hash=scryptSync(password,salt,64).toString('hex'); return `scrypt$${salt}$${hash}`}
function verifyPassword(password,stored){const [scheme,salt,hash]=String(stored||'').split('$'); if(scheme!=='scrypt'||!salt||!hash) return false; const actual=Buffer.from(hash,'hex'); const check=scryptSync(password,salt,64); return actual.length===check.length && timingSafeEqual(actual,check)}
function sign(value){return createHmac('sha256',SESSION_SECRET).update(value).digest('base64url')}
function makeSession(user){const payload=Buffer.from(JSON.stringify({id:user.id,username:user.username,displayName:user.display_name,role:user.role,exp:Date.now()+1000*60*60*12})).toString('base64url'); return `${payload}.${sign(payload)}`}
function parseCookies(req){return Object.fromEntries(String(req.headers.cookie||'').split(';').filter(Boolean).map(p=>{const i=p.indexOf('='); return [p.slice(0,i).trim(),decodeURIComponent(p.slice(i+1))]}))}
function currentUser(req){const token=parseCookies(req).campstore_session; if(!token) return null; const [payload,sig]=token.split('.'); if(!payload||sig!==sign(payload)) return null; try{const data=JSON.parse(Buffer.from(payload,'base64url').toString()); if(data.exp<Date.now()) return null; const user=db.prepare('SELECT id,username,display_name,role,active FROM users WHERE id=? AND active=1').get(data.id); return user?{id:user.id,username:user.username,displayName:user.display_name,role:user.role}:null}catch{return null}}

const PAGE_REGISTRY = [
 {key:'page.clerk',slug:'clerk',label:'Clerk',route:'/clerk',file:'index.html'},
 {key:'page.stock',slug:'stock',label:'Stock',route:'/stock',file:'stock.html'},
 {key:'page.cash_box',slug:'cash-box',label:'Cash Box',route:'/cash-box',file:'cash-box.html'},
 {key:'page.people',slug:'people',label:'People',route:'/people',file:'admin.html'},
 {key:'page.items',slug:'items',label:'Items',route:'/items',file:'admin.html'},
 {key:'page.transactions',slug:'transactions',label:'Transactions',route:'/transactions',file:'admin.html'},
 {key:'page.sync',slug:'sync',label:'Sync',route:'/sync',file:'admin.html'},
 {key:'page.users',slug:'users',label:'Users',route:'/users',file:'admin.html'},
 {key:'page.settings',slug:'settings',label:'Settings',route:'/settings',file:'admin.html'},
 {key:'page.admin',slug:'admin',label:'Admin',route:'/admin',file:'admin.html'}
];
const PAGE_KEYS = new Set(PAGE_REGISTRY.map(p=>p.key));
const ROLE_DEFAULTS = {OWNER:PAGE_REGISTRY.map(p=>p.key),ADMIN:PAGE_REGISTRY.map(p=>p.key),CLERK:['page.clerk']};
function permissionOverrides(userId){return Object.fromEntries(db.prepare('SELECT permission_key,allowed FROM user_page_permissions WHERE user_id=?').all(userId).map(r=>[r.permission_key,!!r.allowed]))}
function getEffectivePermissions(user){const keys={}; for(const p of PAGE_REGISTRY){let allowed=user.role==='OWNER'||(ROLE_DEFAULTS[user.role]||[]).includes(p.key); const ov=permissionOverrides(user.id)[p.key]; if(user.role!=='OWNER'&&ov!==undefined) allowed=ov; keys[p.key]=allowed} return keys}
function userHasPermission(user,key){if(!user||!PAGE_KEYS.has(key)) return false; if(user.role==='OWNER') return true; const ov=db.prepare('SELECT allowed FROM user_page_permissions WHERE user_id=? AND permission_key=?').get(user.id,key); if(ov) return !!ov.allowed; return (ROLE_DEFAULTS[user.role]||[]).includes(key)}
function allowedPages(user){const eff=getEffectivePermissions(user); return PAGE_REGISTRY.filter(p=>eff[p.key])}
function requirePermission(key){return (req,res,next)=>{if(!req.user) return requireAuth(req,res,()=>requirePermission(key)(req,res,next)); if(!userHasPermission(req.user,key)) return wantsHtml(req)?res.status(403).sendFile(path.join(__dirname,'public','403.html')):res.status(403).json({error:'Forbidden'}); next()}}
function requireAnyPermission(keys){return (req,res,next)=>{if(!req.user) return requireAuth(req,res,()=>requireAnyPermission(keys)(req,res,next)); if(!keys.some(k=>userHasPermission(req.user,k))) return res.status(403).json({error:'Forbidden'}); next()}}
function isFinalActiveOwner(id){const u=db.prepare('SELECT role,active FROM users WHERE id=?').get(id); return u&&u.role==='OWNER'&&u.active===1&&db.prepare("SELECT count(*) c FROM users WHERE role='OWNER' AND active=1").get().c<=1}

function requireAuth(req,res,next){const user=currentUser(req); if(!user) return wantsHtml(req)?res.redirect('/login.html'):res.status(401).json({error:'Authentication required'}); req.user=user; next()}
function requireRole(...roles){return (req,res,next)=>{if(!req.user) return requireAuth(req,res,()=>requireRole(...roles)(req,res,next)); const min=Math.min(...roles.map(r=>ROLES[r])); if(ROLES[req.user.role]<min) return wantsHtml(req)?res.status(403).send('Forbidden'):res.status(403).json({error:'Forbidden'}); next()}}
function wantsHtml(req){return (req.headers.accept||'').includes('text/html') || !(req.originalUrl||req.path).startsWith('/api/')}
function cents(v){ if (typeof v === 'number') return Math.round(v*100); const s=String(v||'').replace(/[$,]/g,'').trim(); if(!s) throw Error('missing money value'); const n=Number(s); if(Number.isNaN(n)) throw Error('invalid money value '+v); return Math.round(n*100)}
function optionalOpeningCents(v){const raw=v===undefined||v===null||String(v).trim()===''?0:v; const parsed=cents(raw); if(!Number.isSafeInteger(parsed)) throw Error('Opening balance must be valid integer cents'); if(parsed<0) throw Error('Opening balance cannot be negative'); return parsed}
function money(c){return (c/100).toFixed(2)}
function requestCents(value,label){ if(!Number.isInteger(value)||!Number.isSafeInteger(value)) throw Error(`${label} must be integer cents`); return value }
function createCashDeposit({camperId,amountAddedCents,cashReceivedCents,reason,user,clientRequestId}){ amountAddedCents=requestCents(amountAddedCents,'Amount to add'); cashReceivedCents=requestCents(cashReceivedCents,'Cash received'); if(amountAddedCents<=0) throw Error('Amount to add must be greater than zero'); if(cashReceivedCents<0) throw Error('Cash received cannot be negative'); if(cashReceivedCents<amountAddedCents) throw Error('Insufficient cash received'); const existing=clientRequestId?db.prepare('SELECT ce.*,l.balance_before_cents,l.balance_after_cents,c.name camper_name FROM cash_events ce JOIN account_ledger l ON l.id=ce.account_ledger_id JOIN campers c ON c.id=ce.camper_id WHERE ce.client_request_id=?').get(String(clientRequestId)):null; if(existing) return {ok:true,duplicate:true,cash_event:existing,camperId:existing.camper_id,camperName:existing.camper_name,amount_added_cents:existing.amount_credited_cents,cash_received_cents:existing.cash_received_cents,change_owed_cents:existing.change_given_cents,previous_balance_cents:existing.balance_before_cents,new_balance_cents:existing.balance_after_cents,clerk:existing.created_by_name,created_at:existing.created_at}; const openSession=db.prepare("SELECT * FROM cash_box_sessions WHERE status='open' ORDER BY opened_at DESC,id DESC LIMIT 1").get(); if(!openSession) throw Error('Open the cash box before recording cash.'); const stamp=now(); let result; const run=db.transaction(()=>{ const camper=db.prepare('SELECT * FROM campers WHERE id=?').get(camperId); if(!camper) throw Error('Person not found'); if(!camper.active) throw Error('Inactive people cannot receive cash deposits'); const change=cashReceivedCents-amountAddedCents; const ledger=applyBalanceChange(db,{camperId:camper.id,entryType:'funds_added',deltaCents:amountAddedCents,paymentMethod:'cash',reason:String(reason||'').trim()||null,user,createdAt:stamp,metadata:{source:'cash_deposit',cash_received_cents:cashReceivedCents,change_given_cents:change,client_request_id:clientRequestId||null}}).ledger; const eventId='cash_'+nanoid(); db.prepare('INSERT INTO cash_events(id,account_ledger_id,camper_id,event_type,amount_credited_cents,cash_received_cents,change_given_cents,reason,created_by_user_id,created_by_name,created_at,client_request_id,cash_box_session_id) VALUES(?,?,?,?,?,?,?,?,?,?,?,?,?)').run(eventId,ledger.id,camper.id,'account_deposit',amountAddedCents,cashReceivedCents,change,String(reason||'').trim()||null,user?.id||null,user?.displayName||null,stamp,clientRequestId||null,openSession.id); result={ok:true,id:eventId,ledger_id:ledger.id,camperId:camper.id,camperName:camper.name,amount_added_cents:amountAddedCents,cash_received_cents:cashReceivedCents,change_owed_cents:change,previous_balance_cents:ledger.balance_before_cents,new_balance_cents:ledger.balance_after_cents,clerk:user?.displayName||'',created_at:stamp}; }); run(); event('cash_deposit','ok',`${result.camperName} +${money(amountAddedCents)} cash; change ${money(result.change_owed_cents)}`); return result }

function strictMoneyCents(value,label='Amount'){ if(typeof value==='number' && Number.isInteger(value)){ if(value<0) throw Error(`${label} cannot be negative`); return value; } const raw=String(value??'').trim(); if(!raw) throw Error(`${label} is required`); if(!/^\$?\d+(?:\.\d{1,2})?$/.test(raw.replace(/,/g,''))) throw Error(`${label} must be a valid non-negative currency amount`); const parsed=cents(raw); if(parsed<0) throw Error(`${label} cannot be negative`); return parsed }
function auditCashBox(conn,{action,user,sessionId,details}){conn.prepare('INSERT INTO audit_logs(id,created_at,admin,action,details_json) VALUES(?,?,?,?,?)').run('audit_'+nanoid(),now(),user?.displayName||'',action,JSON.stringify({session_id:sessionId,...(details||{})}))}
function openCashBox({openingAmountCents,user,notes}){openingAmountCents=strictMoneyCents(openingAmountCents,'Opening amount'); const stamp=now(); let session; const run=db.transaction(()=>{ if(db.prepare("SELECT id FROM cash_box_sessions WHERE status='open'").get()) throw Error('A cash-box session is already open'); const info=db.prepare('INSERT INTO cash_box_sessions(opening_amount_cents,opened_at,opened_by_user_id,opened_by_name,status,notes) VALUES(?,?,?,?,?,?)').run(openingAmountCents,stamp,user?.id||null,user?.displayName||'', 'open', notes||null); session=db.prepare('SELECT * FROM cash_box_sessions WHERE id=?').get(info.lastInsertRowid); auditCashBox(db,{action:'cash_box_opened',user,sessionId:session.id,details:{opening_amount_cents:openingAmountCents}}); }); run(); return session}
function correctCashBoxInitial({sessionId,openingAmountCents,reason,user}){openingAmountCents=strictMoneyCents(openingAmountCents,'Corrected opening amount'); reason=String(reason||'').trim(); if(!reason) throw Error('Reason is required'); const stamp=now(); let session; const run=db.transaction(()=>{session=db.prepare("SELECT * FROM cash_box_sessions WHERE id=? AND status='open'").get(sessionId); if(!session) throw Error('Open cash-box session not found'); const prior=session.opening_amount_cents; db.prepare('UPDATE cash_box_sessions SET opening_amount_cents=? WHERE id=?').run(openingAmountCents,session.id); db.prepare('INSERT INTO cash_box_adjustments(cash_box_session_id,adjustment_type,amount_cents,reason,created_by_user_id,created_by_name,created_at,metadata_json) VALUES(?,?,?,?,?,?,?,?)').run(session.id,'initial_correction',openingAmountCents,reason,user?.id||null,user?.displayName||'',stamp,JSON.stringify({prior_opening_amount_cents:prior,new_opening_amount_cents:openingAmountCents})); auditCashBox(db,{action:'cash_box_initial_corrected',user,sessionId:session.id,details:{prior_opening_amount_cents:prior,new_opening_amount_cents:openingAmountCents,reason}}); session=db.prepare('SELECT * FROM cash_box_sessions WHERE id=?').get(session.id);}); run(); return session}
function addCashBoxAdjustment({type,amountCents,reason,user}){amountCents=strictMoneyCents(amountCents,'Amount'); if(amountCents<=0) throw Error('Amount must be greater than zero'); reason=String(reason||'').trim(); if(!reason) throw Error('Reason is required'); if(!['cash_added','cash_removed'].includes(type)) throw Error('Invalid adjustment type'); const stamp=now(); let row; const run=db.transaction(()=>{const session=db.prepare("SELECT * FROM cash_box_sessions WHERE status='open' ORDER BY id DESC LIMIT 1").get(); if(!session) throw Error('Open cash-box session not found'); const info=db.prepare('INSERT INTO cash_box_adjustments(cash_box_session_id,adjustment_type,amount_cents,reason,created_by_user_id,created_by_name,created_at) VALUES(?,?,?,?,?,?,?)').run(session.id,type,amountCents,reason,user?.id||null,user?.displayName||'',stamp); auditCashBox(db,{action:type==='cash_added'?'cash_box_cash_added':'cash_box_cash_removed',user,sessionId:session.id,details:{amount_cents:amountCents,reason}}); row=db.prepare('SELECT * FROM cash_box_adjustments WHERE id=?').get(info.lastInsertRowid);}); run(); return row}
function cashBoxCurrent(){const session=db.prepare("SELECT * FROM cash_box_sessions WHERE status='open' ORDER BY opened_at DESC,id DESC LIMIT 1").get(); const empty={cash_sales_cents:0,account_deposits_credited_cents:0,cash_received_cents:0,change_given_cents:0,manual_cash_added_cents:0,manual_cash_removed_cents:0,expected_cash_cents:0}; if(!session) return {session:null,summary:empty,activity:[]}; const cashRows=db.prepare(`SELECT ce.*,c.name camper_name FROM cash_events ce LEFT JOIN campers c ON c.id=ce.camper_id WHERE (ce.cash_box_session_id=? OR (ce.cash_box_session_id IS NULL AND ce.created_at>=?)) ORDER BY ce.created_at,ce.id`).all(session.id,session.opened_at); const adjs=db.prepare('SELECT * FROM cash_box_adjustments WHERE cash_box_session_id=? ORDER BY created_at,id').all(session.id); const summary={...empty}; for(const r of cashRows){ if(r.event_type==='account_deposit') summary.account_deposits_credited_cents+=r.amount_credited_cents; if(r.event_type==='cash_sale') summary.cash_sales_cents+=r.sale_total_cents||r.net_drawer_change_cents||0; summary.cash_received_cents+=r.cash_received_cents; summary.change_given_cents+=r.change_given_cents; }
 for(const a of adjs){ if(a.adjustment_type==='cash_added') summary.manual_cash_added_cents+=a.amount_cents; if(a.adjustment_type==='cash_removed') summary.manual_cash_removed_cents+=a.amount_cents; }
 summary.expected_cash_cents=session.opening_amount_cents+summary.cash_received_cents-summary.change_given_cents+summary.manual_cash_added_cents-summary.manual_cash_removed_cents;
 const activity=[{created_at:session.opened_at,type:'Initial Cash',person_or_sale:'Cash Box',cash_received_cents:session.opening_amount_cents,change_given_cents:0,net_drawer_change_cents:session.opening_amount_cents,clerk:session.opened_by_name,reason_note:session.notes||''},...cashRows.map(r=>({created_at:r.created_at,type:r.event_type==='account_deposit'?'Account Deposit':'Cash Sale',person_or_sale:r.event_type==='cash_sale'?'Walk-up Cash Sale':r.camper_name,cash_received_cents:r.cash_received_cents,change_given_cents:r.change_given_cents,net_drawer_change_cents:r.cash_received_cents-r.change_given_cents,clerk:r.created_by_name||'',reason_note:r.reason||'',transaction_id:r.transaction_id||'',amount_credited_cents:r.amount_credited_cents})),...adjs.map(a=>({created_at:a.created_at,type:a.adjustment_type==='initial_correction'?'Initial Cash Correction':a.adjustment_type==='cash_added'?'Manual Cash Added':'Manual Cash Removed',person_or_sale:'Cash Box',cash_received_cents:a.adjustment_type==='cash_added'?a.amount_cents:0,change_given_cents:a.adjustment_type==='cash_removed'?a.amount_cents:0,net_drawer_change_cents:a.adjustment_type==='cash_removed'?-a.amount_cents:(a.adjustment_type==='cash_added'?a.amount_cents:0),clerk:a.created_by_name,reason_note:a.reason,metadata_json:a.metadata_json}))].sort((a,b)=>String(a.created_at).localeCompare(String(b.created_at)));
 return {session,summary,activity,notes:'Unlinked legacy cash events use opened_at as the lower boundary for the current session.'}}

function now(){return new Date().toISOString()}

function getSetting(key){return db.prepare('SELECT value FROM settings WHERE key=?').get(key)?.value||''}
function saveSetting(key,value){db.prepare('INSERT INTO settings(key,value) VALUES(?,?) ON CONFLICT(key) DO UPDATE SET value=excluded.value').run(key,String(value||''))}
const DEFAULT_SHEETS = { campers: 'Campers / Balances', logs: 'Logs' };
function extractSpreadsheetId(input){
 const value=String(input||'').trim();
 if(!value) return '';
 const match=value.match(/\/spreadsheets\/d\/([a-zA-Z0-9-_]+)/);
 if(match) return match[1];
 return value;
}
function quoteSheetName(name){return `'${String(name).replace(/'/g,"''")}'`}
function googleConfig(){
 const sheetUrl=getSetting('google_sheet_url')||process.env.GOOGLE_SHEET_URL||'';
 const savedId=getSetting('google_spreadsheet_id')||process.env.GOOGLE_SPREADSHEET_ID||'';
 const spreadsheetId=extractSpreadsheetId(savedId||sheetUrl);
 const sheetNames={
  campers:getSetting('google_campers_sheet_name')||process.env.GOOGLE_CAMPERS_SHEET_NAME||DEFAULT_SHEETS.campers,
  logs:getSetting('google_logs_sheet_name')||process.env.GOOGLE_LOGS_SHEET_NAME||DEFAULT_SHEETS.logs
 };
 const email=getSetting('google_service_account_email')||process.env.GOOGLE_SERVICE_ACCOUNT_EMAIL||'';
 const rawKey=getSetting('google_private_key')||process.env.GOOGLE_PRIVATE_KEY||'';
 const privateKey=rawKey.replace(/\\n/g,'\n');
 return {sheetUrl,spreadsheetId,sheetNames,email,privateKey,source:getSetting('google_spreadsheet_id')?'database':'env'};
}
function googleStatus(){const c=googleConfig(); const pendingTransactions=db.prepare("SELECT count(*) c FROM transactions WHERE sync_status!='synced'").get().c; const pendingAdjustments=db.prepare("SELECT count(*) c FROM balance_adjustments WHERE sync_status!='synced'").get().c; return {configured:!!(c.spreadsheetId&&c.email&&c.privateKey),sheetUrl:c.sheetUrl||'',spreadsheetId:c.spreadsheetId?`configured · ${String(c.spreadsheetId).slice(-4)}`:'missing',spreadsheetIdValue:c.spreadsheetId||'',sheetNames:c.sheetNames,serviceAccountEmail:c.email||'',privateKey:c.privateKey?`configured · ${String(c.privateKey).replace(/\n/g,'').slice(-4)}`:'missing',source:c.source,lastImport:getSetting('last_import')||null,lastSync:getSetting('last_sync')||null,pending:pendingTransactions+pendingAdjustments,pendingGoogleSync:pendingTransactions+pendingAdjustments,pendingTransactions,pendingAdjustments}}
function sheetsClient(){ const c=googleConfig(); if(!c.spreadsheetId) throw Error('Missing spreadsheet ID or Google Sheet URL'); if(!c.email) throw Error('Missing service account email'); if(!c.privateKey) throw Error('Missing private key'); const auth = new google.auth.JWT(c.email, null, c.privateKey, ['https://www.googleapis.com/auth/spreadsheets']); return {sheets:google.sheets({version:'v4', auth}), spreadsheetId:c.spreadsheetId,sheetNames:c.sheetNames};}
async function validateSheetTabs(sheets,spreadsheetId,required){const meta=await sheets.spreadsheets.get({spreadsheetId,fields:'sheets.properties.title'}); const tabs=new Set((meta.data.sheets||[]).map(s=>s.properties.title)); const needed=required||[googleConfig().sheetNames.campers,googleConfig().sheetNames.logs]; const missing=needed.filter(t=>!tabs.has(t)); if(missing.length) throw Error('Invalid tab names. Missing required tab(s): '+missing.join(', ')); return [...tabs]}
async function verifyEditAccess(sheets,spreadsheetId,sheetName){const range=`${quoteSheetName(sheetName)}!A1`; const current=await sheets.spreadsheets.values.get({spreadsheetId,range}); const value=current.data.values?.[0]?.[0]||''; await sheets.spreadsheets.values.update({spreadsheetId,range,valueInputOption:'USER_ENTERED',requestBody:{values:[[value]]}})}
function parseMoneyCell(value,label){try{return cents(value)}catch(e){throw Error(`${label}: ${e.message}`)}}
function parseCsv(text){
 const rows=[]; let row=[], cell='', inQuotes=false; const data=String(text||'').replace(/^\ufeff/,'');
 for(let i=0;i<data.length;i++){const ch=data[i], next=data[i+1]; if(inQuotes){if(ch==='"'&&next==='"'){cell+='"'; i++} else if(ch==='"') inQuotes=false; else cell+=ch} else if(ch==='"') inQuotes=true; else if(ch===','){row.push(cell); cell=''} else if(ch==='\n'){row.push(cell); rows.push(row); row=[]; cell=''} else if(ch==='\r'){} else cell+=ch}
 row.push(cell); if(row.some(v=>String(v).trim()!=='')) rows.push(row); return rows;
}
function itemCsvTemplate(){return 'Cost,Item Name,Category,Active,SKU,Notes\n1.50,Snack,Food,true,SNACK-001,Example item\n'}
function validateItemsCsv(text){
 const rows=parseCsv(text); if(!rows.length) return {headers:[],validRows:[],errors:['CSV is empty'],skipped:0};
 const headers=rows[0].map(h=>String(h).trim()); const idx=Object.fromEntries(headers.map((h,i)=>[h.toLowerCase(),i]));
 const req=['cost','item name','category'], errors=[], validRows=[], seen=new Set(); let skipped=0;
 for(const h of req) if(idx[h]===undefined) errors.push(`Missing required column: ${h==='cost'?'Cost':h==='item name'?'Item Name':'Category'}`);
 if(errors.length) return {headers,validRows,errors,skipped};
 for(const [n,row] of rows.slice(1).entries()){const rowNum=n+2; if(row.every(c=>String(c||'').trim()==='')){skipped++; continue}
  const name=String(row[idx['item name']]||'').trim(), category=String(row[idx.category]||'').trim(), rawCost=String(row[idx.cost]||'').trim();
  if(!rawCost) errors.push(`Row ${rowNum}: missing Cost`); let cost=null; if(rawCost) try{cost=cents(rawCost)}catch{errors.push(`Row ${rowNum}: invalid Cost`)}
  if(!name) errors.push(`Row ${rowNum}: missing Item Name`); if(!category) errors.push(`Row ${rowNum}: missing Category`);
  const key=`${name.toLowerCase()}|${category.toLowerCase()}`; if(name&&category&&seen.has(key)) errors.push(`Row ${rowNum}: duplicate item name in same category (${name} / ${category})`); seen.add(key);
  if(name&&category&&cost!==null) validRows.push({name,category,cost_cents:cost,active:parseBool(row[idx.active],true),sku:String(row[idx.sku]||'').trim(),notes:String(row[idx.notes]||'').trim()});
 }
 return {headers,validRows,errors,skipped};
}
function validatePersonType(value){const type=String(value||'Camper').trim(); return ['Camper','Staff','Other'].includes(type)?type:'Other'}
function parseBool(v,def=true){const s=String(v??'').trim().toLowerCase(); if(!s) return def; return ['1','true','yes','y','active','enabled'].includes(s)?1:0}
function parseStock(v){if(v===undefined||v===null||String(v).trim()==='') return null; const n=Math.round(Number(v)); if(Number.isNaN(n)) throw Error('invalid stock quantity'); return n}
function applyItemsImport(validRows,disableMissing){const stamp=now(); const keep=[]; const run=db.transaction(()=>{for(const item of validRows){const existing=db.prepare('SELECT id FROM items WHERE lower(name)=lower(?) AND lower(category)=lower(?)').get(item.name,item.category); const id=existing?.id||'item_'+nanoid(); keep.push(id); db.prepare('INSERT INTO items(id,name,cost_cents,category,active,sku,notes,updated_at) VALUES(?,?,?,?,?,?,?,?) ON CONFLICT(id) DO UPDATE SET name=excluded.name,cost_cents=excluded.cost_cents,category=excluded.category,active=excluded.active,sku=excluded.sku,notes=excluded.notes,updated_at=excluded.updated_at').run(id,item.name,item.cost_cents,item.category,item.active,item.sku,item.notes,stamp)} if(disableMissing&&keep.length) db.prepare(`UPDATE items SET active=0,updated_at=? WHERE id NOT IN (${keep.map(()=>'?').join(',')})`).run(stamp,...keep)}); run(); event('import_items_csv','ok',`Imported ${validRows.length} CSV items${disableMissing?'; disabled missing items':''}`); return {ok:true,imported:validRows.length,disabledMissing:!!disableMissing,lastImport:stamp}}
// --- Roster / reconciliation import (UltraCamp exports + generic CSV) ---
function rosterTemplate(){return 'Cabin,Child Name,Balance\nWhippoorwill,Aubree Bailes,25.00\nCoyote,Bryce Allred,45.00\nRaccoon,Julian Allen,15.00\n'}
function normHeader(h){return String(h||'').toLowerCase().replace(/[^a-z0-9]/g,'')}
function parseRosterCsv(text){
 const rows=parseCsv(text);
 if(!rows.length) return {format:null,detected:'empty',people:[],errors:['CSV is empty'],skipped:0};
 const headers=rows[0].map(h=>String(h).trim());
 const idx={}; headers.forEach((h,i)=>{const k=normHeader(h); if(idx[k]===undefined) idx[k]=i});
 const has=k=>idx[k]!==undefined;
 const hasFacility=has('facilityname'), hasFirst=has('namefirst'), hasLast=has('namelast'), hasAmount=has('amount'), hasPerson=has('idperson');
 let format,detected,nameCol,cabinCol,balCol;
 if(hasAmount&&(hasFirst||hasLast)){format='ultracamp_deposits'; detected='UltraCamp Store Deposits'}
 else if(hasFacility&&(hasFirst||hasLast)){format='ultracamp_cabins'; detected='UltraCamp Cabin Assignments'}
 else{
  const nameKey=['childname','name','camper','fullname','student'].find(has);
  if(!nameKey&&!(hasFirst||hasLast)) return {format:null,detected:'unknown',people:[],errors:['Could not find a name column. Use a "Child Name" column, or an UltraCamp export with nameFirst/nameLast.'],skipped:0,headers};
  format='generic'; detected='Generic roster CSV';
  nameCol=nameKey!==undefined?idx[nameKey]:undefined;
  const cabinKey=['cabin','facilityname','facility','lodging','group','unit'].find(has); cabinCol=cabinKey!==undefined?idx[cabinKey]:undefined;
  const balKey=['balance','currentbalance','amount','deposit','initialbalance','funds'].find(has); balCol=balKey!==undefined?idx[balKey]:undefined;
 }
 const nameOf=row=>{ if(format==='generic'&&nameCol!==undefined) return String(row[nameCol]||'').trim(); const f=hasFirst?String(row[idx.namefirst]||'').trim():''; const l=hasLast?String(row[idx.namelast]||'').trim():''; return `${f} ${l}`.trim() };
 const cabinOf=row=>format==='generic'?(cabinCol!==undefined?String(row[cabinCol]||'').trim():''):(hasFacility?String(row[idx.facilityname]||'').trim():'');
 const map=new Map(); const errors=[]; let skipped=0;
 for(const [n,row] of rows.slice(1).entries()){
  const rowNum=n+2; if(row.every(c=>String(c||'').trim()==='')){skipped++; continue}
  const name=nameOf(row); if(!name){skipped++; continue}
  const extId=hasPerson?String(row[idx.idperson]||'').trim():'';
  const cabin=cabinOf(row);
  const key=extId?'id:'+extId:'name:'+name.toLowerCase();
  let rec=map.get(key); if(!rec){rec={external_id:extId,name,cabin:'',depositTotal:0,balance:null,hasBalance:false,rows:0}; map.set(key,rec)}
  if(cabin) rec.cabin=cabin; rec.rows++;
  if(format==='ultracamp_deposits'){const raw=String(row[idx.amount]||'').trim(); if(raw){try{rec.depositTotal+=cents(raw); rec.hasBalance=true}catch{errors.push(`Row ${rowNum}: invalid amount "${raw}"`)}}}
  else if(format==='generic'&&balCol!==undefined){const raw=String(row[balCol]||'').trim(); if(raw){try{rec.balance=cents(raw); rec.hasBalance=true}catch{errors.push(`Row ${rowNum}: invalid balance "${raw}"`)}}}
 }
 const people=[...map.values()].map(r=>({external_id:r.external_id||null,name:r.name,cabin:r.cabin||null,hasBalance:r.hasBalance,balance:format==='ultracamp_deposits'?r.depositTotal:r.balance,depositTotal:r.depositTotal,rows:r.rows}));
 return {format,detected,people,errors,skipped,carriesBalance:people.some(p=>p.hasBalance),carriesCabin:people.some(p=>p.cabin)};
}
function findCamperForRoster(p){ if(p.external_id){const byId=db.prepare('SELECT * FROM campers WHERE external_id=?').get(p.external_id); if(byId) return byId} return db.prepare("SELECT * FROM campers WHERE lower(name)=lower(?) ORDER BY (external_id IS NULL), source='manual' DESC LIMIT 1").get(p.name) }
function reconcilePlan(parsed,opts){
 const isDeposit=parsed.format==='ultracamp_deposits';
 const items=[]; const summary={newPeople:0,skippedNew:0,cabinChanges:0,balanceChanges:0,unchanged:0,totalBalanceDelta:0};
 for(const p of parsed.people){
  const existing=findCamperForRoster(p);
  const entry={name:p.name,cabin:p.cabin,external_id:p.external_id,existingId:existing?.id||null};
  if(!existing){ if(!opts.createNew){summary.skippedNew++; continue} entry.type='new'; entry.newBalance=p.hasBalance?p.balance:0; summary.newPeople++; summary.totalBalanceDelta+=entry.newBalance; items.push(entry); continue}
  entry.currentCabin=existing.cabin||null; entry.currentBalance=existing.current_balance_cents;
  let changed=false;
  if(opts.updateCabins&&p.cabin&&(existing.cabin||'')!==p.cabin){entry.cabinChange={from:existing.cabin||null,to:p.cabin}; summary.cabinChanges++; changed=true}
  if(opts.reconcileBalances&&p.hasBalance){
   if(isDeposit){const delta=p.balance-existing.initial_balance_cents; if(delta!==0){entry.balanceChange={mode:'deposit',delta,fromInitial:existing.initial_balance_cents,toInitial:p.balance,fromCurrent:existing.current_balance_cents,toCurrent:existing.current_balance_cents+delta}; summary.balanceChanges++; summary.totalBalanceDelta+=delta; changed=true}}
   else if(p.balance!==existing.current_balance_cents){const delta=p.balance-existing.current_balance_cents; entry.balanceChange={mode:'set',delta,fromCurrent:existing.current_balance_cents,toCurrent:p.balance}; summary.balanceChanges++; summary.totalBalanceDelta+=delta; changed=true}
  }
  entry.type=changed?'update':'unchanged'; if(!changed) summary.unchanged++; items.push(entry);
 }
 return {format:parsed.format,detected:parsed.detected,isDeposit,carriesBalance:parsed.carriesBalance,carriesCabin:parsed.carriesCabin,items,summary,errors:parsed.errors,skipped:parsed.skipped};
}
function applyRoster(parsed,opts,user){
 const plan=reconcilePlan(parsed,opts); const stamp=now(); let created=0,cabinsUpdated=0,balancesReconciled=0;
 const run=db.transaction(()=>{
  for(const e of plan.items){
   if(e.type==='new'){ if(!opts.createNew) continue; const id='roster_'+nanoid(); const bal=e.newBalance||0;
    db.prepare('INSERT INTO campers(id,name,person_type,initial_balance_cents,current_balance_cents,sheet_row,active,notes,source,cabin,external_id,updated_at) VALUES(?,?,?,?,?,?,?,?,?,?,?,?)').run(id,e.name,'Camper',bal,bal,null,1,'',parsed.format==='generic'?'roster':'ultracamp',e.cabin||null,e.external_id||null,stamp);
    const auditId='audit_'+nanoid(); db.prepare('INSERT INTO audit_logs(id,created_at,admin,action,person_id,person_name,initial_balance_cents,current_balance_cents,details_json) VALUES(?,?,?,?,?,?,?,?,?)').run(auditId,stamp,user.displayName,'roster_person_create',id,e.name,bal,bal,JSON.stringify({cabin:e.cabin||null,external_id:e.external_id||null,source:parsed.detected})); recordOpeningLedger(db,{camperId:id,balanceCents:bal,auditLogId:auditId,user,createdAt:stamp,metadata:{source:'roster_import',import_source:parsed.detected}}); created++; continue }
   if(e.type!=='update') continue;
   if(e.external_id) db.prepare('UPDATE campers SET external_id=COALESCE(external_id,?) WHERE id=?').run(e.external_id,e.existingId);
   if(e.cabinChange){db.prepare('UPDATE campers SET cabin=?,updated_at=? WHERE id=?').run(e.cabinChange.to,stamp,e.existingId); cabinsUpdated++}
   if(e.balanceChange){const bc=e.balanceChange;
    if(bc.mode==='deposit') db.prepare('UPDATE campers SET initial_balance_cents=?,updated_at=? WHERE id=?').run(bc.toInitial,stamp,e.existingId);
    const adjId='adj_'+nanoid(); db.prepare('INSERT INTO balance_adjustments(id,created_at,admin,camper_id,camper_name,action,amount_cents,previous_balance_cents,new_balance_cents,reason) VALUES(?,?,?,?,?,?,?,?,?,?)').run(adjId,stamp,user.displayName,e.existingId,e.name,bc.mode==='deposit'?'reconcile_deposit':'reconcile_set',bc.delta,bc.fromCurrent,bc.toCurrent,`Reconciliation import (${parsed.detected})`); applyBalanceChange(db,{camperId:e.existingId,entryType:'reconciliation',setBalanceCents:bc.toCurrent,balanceAdjustmentId:adjId,reason:`Reconciliation import (${parsed.detected})`,user,createdAt:stamp,metadata:{source:'roster_import',import_source:parsed.detected,mode:bc.mode,old_opening_balance_cents:bc.fromInitial,new_opening_balance_cents:bc.toInitial}}); balancesReconciled++ }
  }
 }); run();
 saveSetting('last_reconcile',stamp);
 event('roster_import','ok',`Reconciliation (${parsed.detected}): ${created} new, ${cabinsUpdated} cabin updates, ${balancesReconciled} balance adjustments`);
 return {ok:true,created,cabinsUpdated,balancesReconciled,summary:plan.summary,detected:parsed.detected,format:parsed.format,lastReconcile:stamp};
}
// --- CSV export ---
function csvCell(v){const s=String(v==null?'':v); return /[",\n\r]/.test(s)?'"'+s.replace(/"/g,'""')+'"':s}
function toCsv(headers,rows){return [headers.map(csvCell).join(','),...rows.map(r=>r.map(csvCell).join(','))].join('\r\n')+'\r\n'}
function sendCsv(res,filename,csv){res.type('text/csv').attachment(filename).send(csv)}

async function importCampers(){const {sheets,spreadsheetId,sheetNames}=sheetsClient(); await validateSheetTabs(sheets,spreadsheetId,[sheetNames.campers]); const r=await sheets.spreadsheets.values.get({spreadsheetId,range:`${quoteSheetName(sheetNames.campers)}!A2:C`}); const rows=r.data.values||[], seen=new Set(), warnings=[]; const stamp=now(); let imported=0, skipped=0; const run=db.transaction(()=>{for(const [i,row] of rows.entries()){if(!row[0]&&!row[1]&&!row[2]){skipped++; continue} if(!row[0]) throw Error(`${sheetNames.campers} row ${i+2}: missing child name`); const name=String(row[0]).trim(); const key=name.toLowerCase(); if(seen.has(key)) throw Error('Duplicate camper name: '+name); seen.add(key); const initial=parseMoneyCell(row[1],`${sheetNames.campers} row ${i+2} opening balance`); const current=parseMoneyCell(row[2],`${sheetNames.campers} row ${i+2} current balance`); const existing=db.prepare("SELECT * FROM campers WHERE lower(name)=lower(?) ORDER BY source='manual' DESC LIMIT 1").get(name); const id=existing?.id||'camper_'+Buffer.from(key).toString('hex').slice(0,32); if(existing){db.prepare('UPDATE campers SET name=?,person_type=COALESCE(person_type,?),sheet_row=?,active=1,source=?,updated_at=? WHERE id=?').run(name,'Camper',i+2,'google',stamp,id); if(existing.current_balance_cents!==current) applyBalanceChange(db,{camperId:id,entryType:'import_adjustment',setBalanceCents:current,createdAt:stamp,metadata:{source:'google_import',sheet_row:i+2,previous_initial_balance_cents:existing.initial_balance_cents,new_initial_balance_cents:initial}})} else {db.prepare('INSERT INTO campers(id,name,person_type,initial_balance_cents,current_balance_cents,sheet_row,active,source,updated_at) VALUES(?,?,?,?,?,?,?,?,?)').run(id,name,'Camper',initial,current,i+2,1,'google',stamp); recordOpeningLedger(db,{camperId:id,balanceCents:initial,createdAt:stamp,metadata:{source:'google_import',sheet_row:i+2,authoritative_current_balance_cents:current}})} imported++}}); run(); saveSetting('last_import',stamp); event('import_campers','ok',`Imported ${imported} campers; skipped ${skipped} blank rows`); return {ok:true,imported,skipped,warnings,lastImport:stamp}}
async function syncPending(){const {sheets,spreadsheetId,sheetNames}=sheetsClient(); await validateSheetTabs(sheets,spreadsheetId,[sheetNames.campers,sheetNames.logs]); const pending=db.prepare("SELECT * FROM transactions WHERE sync_status!='synced' ORDER BY created_at").all(); const adjustments=db.prepare("SELECT * FROM balance_adjustments WHERE sync_status!='synced' ORDER BY created_at").all(); for(const t of pending){await sheets.spreadsheets.values.append({spreadsheetId,range:`${quoteSheetName(sheetNames.logs)}!A:I`,valueInputOption:'USER_ENTERED',requestBody:{values:[[t.created_at,t.clerk,t.sale_type==='cash'?'CASH SALE':t.camper_name,t.previous_balance_cents==null?'':money(t.previous_balance_cents),money(t.total_cents),t.new_balance_cents==null?'':money(t.new_balance_cents),JSON.parse(t.items_json).map(i=>`${i.qty}x ${i.name} @ $${money(i.price_cents)}`).join('; '),t.id,t.sale_type==='cash'?'cash_sale':'sale']]}}); if(t.sale_type!=='cash'){const camper=db.prepare('SELECT sheet_row FROM campers WHERE id=?').get(t.camper_id); if(camper?.sheet_row) await sheets.spreadsheets.values.update({spreadsheetId,range:`${quoteSheetName(sheetNames.campers)}!C${camper.sheet_row}`,valueInputOption:'USER_ENTERED',requestBody:{values:[[money(t.new_balance_cents)]]}}); } db.prepare("UPDATE transactions SET sync_status='synced',synced_at=?,error=NULL WHERE id=?").run(now(),t.id)} for(const a of adjustments){await sheets.spreadsheets.values.append({spreadsheetId,range:`${quoteSheetName(sheetNames.logs)}!A:I`,valueInputOption:'USER_ENTERED',requestBody:{values:[[a.created_at,a.admin,a.camper_name,money(a.previous_balance_cents),a.amount_cents==null?'':money(a.amount_cents),money(a.new_balance_cents),`${a.action}: ${a.reason}`,a.id,'balance_adjustment']]}}); const camper=db.prepare('SELECT sheet_row FROM campers WHERE id=?').get(a.camper_id); if(camper?.sheet_row) await sheets.spreadsheets.values.update({spreadsheetId,range:`${quoteSheetName(sheetNames.campers)}!C${camper.sheet_row}`,valueInputOption:'USER_ENTERED',requestBody:{values:[[money(a.new_balance_cents)]]}}); db.prepare("UPDATE balance_adjustments SET sync_status='synced',synced_at=?,error=NULL WHERE id=?").run(now(),a.id)} const stamp=now(); saveSetting('last_sync',stamp); event('sync','ok',`Synced ${pending.length} transactions and ${adjustments.length} adjustments`); return {ok:true,synced:pending.length,adjustmentsSynced:adjustments.length,lastSync:stamp}}

function parseJsonSafe(text,fallback=null){try{return JSON.parse(text)}catch{return fallback}}
function normalizedEntryLabel(type){return ({purchase:'Purchase',funds_added:'Funds added',funds_subtracted:'Funds removed',balance_set:'Balance set',manual_adjustment:'Adjustment',reconciliation:'Reconciliation',opening_balance:'Opening balance',opening_balance_correction:'Opening balance corrected',import_adjustment:'Import adjustment'})[type]||String(type||'Ledger entry').replace(/_/g,' ').replace(/^./,c=>c.toUpperCase())}
function normalizePurchaseItems(itemsJson){const parsed=parseJsonSafe(itemsJson, null); if(!Array.isArray(parsed)) return {items:[],available:false,error:'Purchase details unavailable'}; const items=[]; for(const raw of parsed){if(!raw||typeof raw!=='object') continue; const name=String(raw.name||raw.item_name||raw.title||'Item').trim()||'Item'; const quantity=Math.max(1,Math.round(Number(raw.qty??raw.quantity??1))||1); const unit=Number.isInteger(raw.unit_price_cents)?raw.unit_price_cents:Number.isInteger(raw.price_cents)?raw.price_cents:Number.isInteger(raw.cost_cents)?raw.cost_cents:null; const line=Number.isInteger(raw.line_total_cents)?raw.line_total_cents:(unit==null?null:unit*quantity); items.push({name,quantity,unit_price_cents:unit,line_total_cents:line}); } return {items,available:items.length>0,error:items.length?'':'Purchase details unavailable'} }
function buildHistoryEntry(row){const metadata=parseJsonSafe(row.metadata_json,null); const entry={id:row.id,entry_type:row.entry_type,amount_cents:row.amount_cents,balance_before_cents:row.balance_before_cents,balance_after_cents:row.balance_after_cents,payment_method:row.payment_method,reason:row.reason,created_at:row.created_at,created_by_name:row.created_by_name,transaction_id:row.transaction_id,balance_adjustment_id:row.balance_adjustment_id,metadata_json:row.metadata_json,metadata,display_label:normalizedEntryLabel(row.entry_type),source_label:metadata?.source?normalizedEntryLabel(metadata.source):normalizedEntryLabel(row.entry_type)}; if(row.tx_id&&row.tx_camper_id===row.camper_id){const norm=normalizePurchaseItems(row.tx_items_json); entry.purchase={items:norm.items,total_cents:row.tx_total_cents,details_available:norm.available}; if(!norm.available) entry.purchase.error=norm.error;} else if(row.transaction_id){entry.purchase={items:[],total_cents:null,details_available:false,error:'Purchase details unavailable'};} if(row.cash_event_id&&row.cash_camper_id===row.camper_id){entry.cash_event={event_type:row.cash_event_type,amount_credited_cents:row.cash_amount_credited_cents,cash_received_cents:row.cash_received_cents,change_given_cents:row.cash_change_given_cents,reason:row.cash_reason}; entry.display_label='Cash added to account';}
 if(row.adj_id&&row.adj_camper_id===row.camper_id){entry.adjustment={action:row.adj_action,reason:row.adj_reason,administrator_name:row.adj_admin,amount_cents:row.adj_amount_cents,previous_balance_cents:row.adj_previous_balance_cents,new_balance_cents:row.adj_new_balance_cents};} else if(row.balance_adjustment_id){entry.adjustment={details_available:false,error:'Adjustment details unavailable'};} return entry}

function event(type,status,message){db.prepare('INSERT INTO sync_events(created_at,type,status,message) VALUES(?,?,?,?)').run(now(),type,status,message||'')}
