app.post('/api/campers/:id/opening-balance-correction',requireRole('ADMIN','OWNER'),(req,res)=>{try{const reason=String(req.body?.reason||'').trim(); if(!reason) return res.status(400).json({error:'Reason is required'}); const corrected=optionalOpeningCents(req.body?.opening_balance ?? req.body?.initial_balance); const camper=db.prepare('SELECT * FROM campers WHERE id=?').get(req.params.id); if(!camper) return res.status(404).json({error:'Camper not found'}); const delta=corrected-camper.initial_balance_cents; const nextCurrent=camper.current_balance_cents+delta; const stamp=now(), auditId='audit_'+nanoid(); const run=db.transaction(()=>{db.prepare('UPDATE campers SET initial_balance_cents=?,current_balance_cents=?,updated_at=? WHERE id=?').run(corrected,nextCurrent,stamp,camper.id); db.prepare('INSERT INTO audit_logs(id,created_at,admin,action,person_id,person_name,initial_balance_cents,current_balance_cents,details_json) VALUES(?,?,?,?,?,?,?,?,?)').run(auditId,stamp,req.user.displayName,'opening_balance_correction',camper.id,camper.name,corrected,nextCurrent,JSON.stringify({reason,old_opening_balance_cents:camper.initial_balance_cents,new_opening_balance_cents:corrected,delta_cents:delta,previous_current_balance_cents:camper.current_balance_cents,new_current_balance_cents:nextCurrent})); insertAccountLedger(db,{camper_id:camper.id,entry_type:'opening_balance_correction',amount_cents:delta,balance_before_cents:camper.current_balance_cents,balance_after_cents:nextCurrent,reason,audit_log_id:auditId,created_by_user_id:req.user.id,created_by_name:req.user.displayName,created_at:stamp,metadata_json:{source:'opening_balance_correction',old_opening_balance_cents:camper.initial_balance_cents,new_opening_balance_cents:corrected}})}); run(); res.json({ok:true,initial_balance_cents:corrected,current_balance_cents:nextCurrent,delta_cents:delta})}catch(e){res.status(400).json({error:e.message})}});
app.post('/api/campers/:id/adjust',requireRole('ADMIN','OWNER'),(req,res)=>{try{const {action,amount,reason}=req.body||{}; if(!String(reason||'').trim()) throw Error('Reason is required'); const camper=db.prepare('SELECT * FROM campers WHERE id=?').get(req.params.id); if(!camper) return res.status(404).json({error:'Camper not found'}); let amt=action==='set'?null:cents(amount); let next=action==='add'?camper.current_balance_cents+amt:action==='subtract'?camper.current_balance_cents-amt:action==='set'?cents(amount):null; if(next===null) throw Error('Invalid adjustment action'); const id='adj_'+nanoid(), stamp=now(); const entryType=action==='add'?'funds_added':action==='subtract'?'funds_subtracted':'balance_set'; const run=db.transaction(()=>{db.prepare('INSERT INTO balance_adjustments(id,created_at,admin,camper_id,camper_name,action,amount_cents,previous_balance_cents,new_balance_cents,reason) VALUES(?,?,?,?,?,?,?,?,?,?)').run(id,stamp,req.user.displayName,camper.id,camper.name,action,amt,camper.current_balance_cents,next,String(reason).trim()); applyBalanceChange(db,{camperId:camper.id,entryType,setBalanceCents:next,balanceAdjustmentId:id,reason:String(reason).trim(),user:req.user,createdAt:stamp,metadata:{source:'manual_adjustment',action}})}); run(); res.json({ok:true,id,new_balance_cents:next})}catch(e){res.status(400).json({error:e.message})}});
