app.post('/api/settings',requireRole('ADMIN','OWNER'),(req,res)=>{for(const [k,v] of Object.entries(req.body||{})) db.prepare('INSERT INTO settings(key,value) VALUES(?,?) ON CONFLICT(key) DO UPDATE SET value=excluded.value').run(k,String(v)); res.json({ok:true})});
function buildSaleItems(cart){if(!Array.isArray(cart)||!cart.length) throw Error('Cart is empty'); return cart.map(ci=>{const item=db.prepare('SELECT * FROM items WHERE id=? AND active=1').get(ci.id); if(!item) throw Error('Item not found'); const qty=Number(ci.qty); if(!Number.isInteger(qty)||qty<1) throw Error('Invalid quantity'); if(item.stock_qty!==null&&item.stock_qty<qty) throw Error('Insufficient stock for '+item.name); return {id:item.id,name:item.name,price_cents:item.cost_cents,qty,line_total_cents:item.cost_cents*qty}})}
function createSale({saleType,camperId,cart,allowOverride,cashReceivedCents,clientRequestId,user}){saleType=String(saleType||'account'); if(!['account','cash'].includes(saleType)) throw Error('Malformed saleType'); const existing=clientRequestId?db.prepare('SELECT * FROM transactions WHERE client_request_id=?').get(String(clientRequestId)):null; if(existing) return {ok:true,duplicate:true,id:existing.id,sale_type:existing.sale_type,camperId:existing.camper_id,new_balance_cents:existing.new_balance_cents,cash_received_cents:existing.cash_received_cents,change_given_cents:existing.change_given_cents,total_cents:existing.total_cents}; const items=buildSaleItems(cart), total=items.reduce((a,i)=>a+i.line_total_cents,0), txid='tx_'+nanoid(), created=now(); let result; const run=db.transaction(()=>{if(saleType==='cash'){cashReceivedCents=requestCents(cashReceivedCents,'Cash received'); if(cashReceivedCents<0) throw Error('Cash received cannot be negative'); if(cashReceivedCents<total) throw Error('Insufficient cash received'); if(!db.prepare("SELECT id FROM cash_box_sessions WHERE status='open'").get()) throw Error('The cash box must be opened before recording cash sales.')} for(const it of items){const r=db.prepare('UPDATE items SET stock_qty=stock_qty-? WHERE id=? AND stock_qty IS NOT NULL AND stock_qty>=?').run(it.qty,it.id,it.qty); const cur=db.prepare('SELECT stock_qty FROM items WHERE id=?').get(it.id); if(cur.stock_qty!==null&&r.changes!==1) throw Error('Insufficient stock for '+it.name); db.prepare('INSERT INTO stock_adjustments(id,item_id,quantity_change,resulting_quantity,adjustment_type,reason,user_id,created_at) VALUES(?,?,?,?,?,?,?,?)').run('stock_'+nanoid(),it.id,it.qty,cur.stock_qty??0,'sale','Sale '+txid,user?.id||null,created)} if(saleType==='account'){const camper=db.prepare('SELECT * FROM campers WHERE id=? AND active=1').get(camperId); if(!camper) throw Error('Camper not found'); const allow=db.prepare("SELECT value FROM settings WHERE key='allow_over_balance'").get()?.value==='true'; if(camper.current_balance_cents-total<0&&!allow&&!allowOverride) throw Error('Purchase exceeds current balance'); db.prepare('INSERT INTO transactions(id,created_at,clerk,camper_id,camper_name,previous_balance_cents,total_cents,new_balance_cents,items_json,sale_type,payment_method,client_request_id) VALUES(?,?,?,?,?,?,?,?,?,?,?,?)').run(txid,created,user.displayName,camper.id,camper.name,camper.current_balance_cents,total,camper.current_balance_cents-total,JSON.stringify(items),'account','account',clientRequestId||null); applyBalanceChange(db,{camperId:camper.id,entryType:'purchase',deltaCents:-total,transactionId:txid,user,createdAt:created,metadata:{source:'sale',item_count:items.length,total_cents:total}}); result={ok:true,id:txid,camperId:camper.id,new_balance_cents:camper.current_balance_cents-total,total_cents:total,sale_type:'account'}; return} const session=db.prepare("SELECT * FROM cash_box_sessions WHERE status='open' ORDER BY opened_at DESC,id DESC LIMIT 1").get(); const change=cashReceivedCents-total; db.prepare('INSERT INTO transactions(id,created_at,clerk,camper_id,camper_name,previous_balance_cents,total_cents,new_balance_cents,items_json,sale_type,payment_method,cash_box_session_id,cash_received_cents,change_given_cents,client_request_id) VALUES(?,?,?,?,?,?,?,?,?,?,?,?,?,?,?)').run(txid,created,user.displayName,null,'Walk-up Cash Sale',null,total,null,JSON.stringify(items),'cash','cash',session.id,cashReceivedCents,change,clientRequestId||null); db.prepare('INSERT INTO cash_events(id,account_ledger_id,camper_id,event_type,amount_credited_cents,cash_received_cents,change_given_cents,reason,created_by_user_id,created_by_name,created_at,client_request_id,cash_box_session_id,transaction_id,sale_total_cents,net_drawer_change_cents) VALUES(?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?)').run('cash_'+nanoid(),null,null,'cash_sale',0,cashReceivedCents,change,'Walk-up Cash Sale',user?.id||null,user?.displayName||null,created,clientRequestId||null,session.id,txid,total,total); result={ok:true,id:txid,sale_type:'cash',total_cents:total,cash_received_cents:cashReceivedCents,change_given_cents:change,cash_box_session_id:session.id};}); run(); event('sale','ok',saleType+' sale '+txid+' '+money(total)); if(result.sale_type==='cash') result.cash_box_expected_cents=cashBoxCurrent().summary.expected_cash_cents; return result}

function saleErrorCode(message){const m=String(message||''); if(/cash box must be opened/i.test(m)) return 'CASH_BOX_NOT_OPEN'; if(/Insufficient cash|Cash received/i.test(m)) return 'INSUFFICIENT_CASH'; if(/Insufficient stock/i.test(m)) return 'INSUFFICIENT_STOCK'; if(/Item not found|Invalid quantity|Cart is empty|Malformed saleType/i.test(m)) return 'INVALID_ITEM'; if(/UNIQUE constraint failed.*client_request_id|duplicate/i.test(m)) return 'DUPLICATE_REQUEST'; return 'CASH_SALE_FAILED'}
function friendlySaleError(code,message){return ({CASH_BOX_NOT_OPEN:'Open the cash box before completing cash sales.',INSUFFICIENT_CASH:'Cash received is not enough for this sale.',INSUFFICIENT_STOCK:message,INVALID_ITEM:message,DUPLICATE_REQUEST:'This sale request was already recorded.',CASH_SALE_FAILED:'Cash sale could not be completed'})[code]||'Cash sale could not be completed'}
app.post('/api/sale',requirePermission('page.clerk'),(req,res)=>{try{const {saleType,camperId,cart,allowOverride,cashReceivedCents,clientRequestId}=req.body||{}; res.json(createSale({saleType,camperId,cart,allowOverride,cashReceivedCents,clientRequestId,user:req.user}))}catch(e){const code=saleErrorCode(e.message); console.error('[sale] failed', {code,message:e.message,stack:e.stack}); res.status(400).json({error:friendlySaleError(code,e.message),code})}});


app.get('/api/settings/google',requireRole('ADMIN','OWNER'),(req,res)=>res.json(googleStatus()));
app.post('/api/settings/google',requireRole('ADMIN','OWNER'),(req,res)=>{try{let {sheetUrl,spreadsheetId,campersSheetName,logsSheetName,serviceAccountEmail,privateKey,serviceAccountJson}=req.body||{}; if(serviceAccountJson){const parsed=typeof serviceAccountJson==='string'?JSON.parse(serviceAccountJson):serviceAccountJson; spreadsheetId=spreadsheetId||parsed.spreadsheet_id||parsed.spreadsheetId; serviceAccountEmail=serviceAccountEmail||parsed.client_email; privateKey=privateKey||parsed.private_key} sheetUrl=String(sheetUrl||spreadsheetId||'').trim(); spreadsheetId=extractSpreadsheetId(spreadsheetId||sheetUrl); campersSheetName=String(campersSheetName||DEFAULT_SHEETS.campers).trim(); logsSheetName=String(logsSheetName||DEFAULT_SHEETS.logs).trim(); serviceAccountEmail=String(serviceAccountEmail||'').trim(); privateKey=String(privateKey||'').trim(); if(!spreadsheetId) return res.status(400).json({error:'Missing Google Sheet URL or spreadsheet ID'}); if(!campersSheetName||!logsSheetName) return res.status(400).json({error:'Missing one or more tab names'}); if(!serviceAccountEmail) return res.status(400).json({error:'Missing service account email'}); if(!privateKey && !getSetting('google_private_key') && !process.env.GOOGLE_PRIVATE_KEY) return res.status(400).json({error:'Missing private key'}); saveSetting('google_sheet_url',sheetUrl); saveSetting('google_spreadsheet_id',spreadsheetId); saveSetting('google_campers_sheet_name',campersSheetName); saveSetting('google_logs_sheet_name',logsSheetName); saveSetting('google_service_account_email',serviceAccountEmail); if(privateKey) saveSetting('google_private_key',privateKey); res.json({ok:true,google:googleStatus()})}catch(e){res.status(400).json({error:'Invalid service account JSON or settings: '+e.message})}});
app.post('/api/google/test',requireRole('ADMIN','OWNER'),async(req,res)=>{try{const {sheets,spreadsheetId,sheetNames}=sheetsClient(); const required=[sheetNames.campers,sheetNames.logs]; const tabs=await validateSheetTabs(sheets,spreadsheetId,required); await verifyEditAccess(sheets,spreadsheetId,sheetNames.logs); event('google_test','ok','Google Sheets connection test succeeded'); res.json({ok:true,message:'Google Sheets connection successful; required tabs exist and edit access verified',tabs,requiredTabs:required,status:googleStatus()})}catch(e){event('google_test','error',e.message); res.status(400).json({error:e.message,status:googleStatus()})}});
app.post('/api/google/import/campers',requireRole('ADMIN','OWNER'),async(req,res)=>{try{res.json(await importCampers())}catch(e){event('import_campers','error',e.message); res.status(400).json({error:e.message})}});
app.post('/api/google/sync-pending',requireRole('ADMIN','OWNER'),async(req,res)=>{try{res.json(await syncPending())}catch(e){event('sync','error',e.message); db.prepare("UPDATE transactions SET sync_status='error',error=? WHERE sync_status!='synced'").run(e.message); res.status(400).json({error:e.message})}});
app.post('/api/import',requireRole('ADMIN','OWNER'),async(req,res)=>{try{const campers=await importCampers(); res.json({ok:true,campers})}catch(e){event('import','error',e.message); res.status(400).json({error:e.message})}});
app.post('/api/sync',requireRole('ADMIN','OWNER'),async(req,res)=>{try{res.json(await syncPending())}catch(e){event('sync','error',e.message); db.prepare("UPDATE transactions SET sync_status='error',error=? WHERE sync_status!='synced'").run(e.message); res.status(400).json({error:e.message})}});
app.get('/api/status',requirePermission('page.admin'),async(req,res)=>{let gs=googleStatus(); const today=new Date().toISOString().slice(0,10); const LOW=Number(process.env.LOW_STOCK_THRESHOLD||5); res.json({database:{path:DB_PATH,ok:true},stats:{campers:db.prepare('SELECT count(*) c FROM campers WHERE active=1').get().c,cabins:db.prepare("SELECT count(*) c FROM (SELECT DISTINCT cabin FROM campers WHERE active=1 AND cabin IS NOT NULL AND TRIM(cabin)!='')").get().c,campersWithoutCabin:db.prepare("SELECT count(*) c FROM campers WHERE active=1 AND (cabin IS NULL OR TRIM(cabin)='')").get().c,items:db.prepare('SELECT count(*) c FROM items WHERE active=1').get().c,itemsByCategory:db.prepare('SELECT category,count(*) c FROM items WHERE active=1 GROUP BY category ORDER BY category').all(),trackedItems:db.prepare('SELECT count(*) c FROM items WHERE active=1 AND stock_qty IS NOT NULL').get().c,lowStock:db.prepare('SELECT count(*) c FROM items WHERE active=1 AND stock_qty IS NOT NULL AND stock_qty<=?').get(LOW).c,outOfStock:db.prepare('SELECT count(*) c FROM items WHERE active=1 AND stock_qty IS NOT NULL AND stock_qty<=0').get().c,lowStockThreshold:LOW,salesToday:db.prepare("SELECT count(*) c FROM transactions WHERE substr(created_at,1,10)=?").get(today).c,revenueToday:db.prepare("SELECT coalesce(sum(total_cents),0) c FROM transactions WHERE substr(created_at,1,10)=?").get(today).c},lastReconcile:getSetting('last_reconcile')||null,googleStatus:gs.configured?'configured':'not configured',google:gs,lastImport:gs.lastImport,lastSync:gs.lastSync,pending:gs.pending,pendingGoogleSync:gs.pendingGoogleSync,version:APP_VERSION,events:db.prepare('SELECT * FROM sync_events ORDER BY id DESC LIMIT 30').all()})});
app.get('/api/users',requirePermission('page.users'),(req,res)=>res.json({pages:PAGE_REGISTRY,users:db.prepare('SELECT id,username,display_name,role,active,created_at,updated_at FROM users ORDER BY username').all().map(u=>({...u,permissionOverrides:permissionOverrides(u.id),effectivePermissions:getEffectivePermissions({id:u.id,role:u.role})}))}));
app.post('/api/users',requirePermission('page.users'),(req,res)=>{const {username,password,displayName,role}=req.body||{}; if(role==='OWNER'&&req.user.role!=='OWNER') return res.status(403).json({error:'Only OWNER can create OWNER accounts'}); if(!username||!password||!ROLES[role]) return res.status(400).json({error:'username, password, and role are required'}); const stamp=now(); db.prepare('INSERT INTO users(id,username,display_name,role,password_hash,active,created_at,updated_at) VALUES(?,?,?,?,?,?,?,?)').run('user_'+nanoid(),username,displayName||username,role,hashPassword(password),1,stamp,stamp); res.json({ok:true})});
app.post('/api/users/:id/permissions',requirePermission('page.users'),(req,res)=>{try{const target=db.prepare('SELECT id,role,active FROM users WHERE id=?').get(req.params.id); if(!target) return res.status(404).json({error:'User not found'}); if(req.user.role!=='OWNER' && target.role==='OWNER') return res.status(403).json({error:'Only OWNER can modify OWNER accounts'}); const permissions=req.body?.permissions||{}; const stamp=now(); const run=db.transaction(()=>{db.prepare('DELETE FROM user_page_permissions WHERE user_id=?').run(target.id); for(const [key,val] of Object.entries(permissions)){if(!PAGE_KEYS.has(key)) continue; if(target.role==='OWNER') continue; if(val==='allow'||val===true||val===1) db.prepare('INSERT INTO user_page_permissions(user_id,permission_key,allowed,created_at,updated_at) VALUES(?,?,?,?,?)').run(target.id,key,1,stamp,stamp); else if(val==='deny'||val===false||val===0) db.prepare('INSERT INTO user_page_permissions(user_id,permission_key,allowed,created_at,updated_at) VALUES(?,?,?,?,?)').run(target.id,key,0,stamp,stamp)}}); run(); res.json({ok:true})}catch(e){res.status(400).json({error:e.message})}});
app.post('/api/users/:id/status',requirePermission('page.users'),(req,res)=>{try{if(isFinalActiveOwner(req.params.id) && req.body?.active===false) return res.status(400).json({error:'Cannot disable the final active OWNER'}); db.prepare('UPDATE users SET active=?,updated_at=? WHERE id=?').run(req.body?.active===false?0:1,now(),req.params.id); res.json({ok:true})}catch(e){res.status(400).json({error:e.message})}});
app.post('/api/users/:id/password',requireRole('OWNER'),(req,res)=>{if(!req.body?.password) return res.status(400).json({error:'password is required'}); db.prepare('UPDATE users SET password_hash=?,updated_at=? WHERE id=?').run(hashPassword(req.body.password),now(),req.params.id); res.json({ok:true})});
if (require.main === module) app.listen(process.env.PORT||3077,()=>console.log(`Camp Store POS running on ${process.env.PORT||3077}`));
